queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCoverage ?child ; p:hasInsurance_Plan ?parent . } GROUP BY ?child }
  ?child p:Description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :InsurancePlans } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?planname ?description WHERE {
  ?insurance_plan_coverage a :Insurance_Plan_Coverage .
  ?coverage a :Coverage .
  ?insurance_plan_coverage p:hasCoverage ?coverage .
  ?insurance_plan a :InsurancePlans .
  ?insurance_plan_coverage p:hasInsurance_Plan ?insurance_plan .
  ?insurance_plan p:PlanName ?planname .
  ?coverage p:Description ?description .
} }
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCoverage ?child ; p:hasInsurance_Plan ?parent . } GROUP BY ?child }
  ?child p:Description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :InsurancePlans } }
  FILTER(?nf = ?total)
} }
}
